    /**
     * Preview vulnerabilities that would be affected by an exception
     * Feature 021 Phase 3: For impact preview before creating exception
     *
     * Uses SQL-level queries to avoid loading all vulnerabilities into memory.
     * Gets the total count via COUNT queries and a small sample via paginated queries.
     *
     * @param exceptionType Type of exception (IP/PRODUCT/ASSET/CVE)
     * @param targetValue Target value (IP address, product name, CVE IDs)
     * @param assetId Asset ID (for ASSET type or CVE single-system scope)
     * @param limit Maximum number of vulnerabilities to return (default: 10)
     * @return Pair of (affected vulnerabilities sample, total count)
     */
    fun previewExceptionImpact(
        exceptionType: com.secman.domain.VulnerabilityException.ExceptionType,
        targetValue: String,
        assetId: Long? = null,
        limit: Int = 10
    ): Pair<List<VulnerabilityWithExceptionDto>, Int> {
        log.debug("Previewing exception impact - type: {}, target: {}, assetId: {}",
            exceptionType, targetValue, assetId)

        val pageable = io.micronaut.data.model.Pageable.from(0, limit)

        // Get count and sample using SQL-level queries per exception type
        val (sampleVulns, totalCount) = when (exceptionType) {
            com.secman.domain.VulnerabilityException.ExceptionType.IP -> {
                val count = vulnerabilityRepository.countByAssetIp(targetValue).toInt()
                val page = vulnerabilityRepository.findByAssetIp(targetValue, pageable)
                Pair(page.content, count)
            }
            com.secman.domain.VulnerabilityException.ExceptionType.PRODUCT -> {
                val count = vulnerabilityRepository.countByVulnerableProductVersionsContainingIgnoreCase(targetValue).toInt()
                val page = vulnerabilityRepository.findByVulnerableProductVersionsContainingIgnoreCase(targetValue, pageable)
                Pair(page.content, count)
            }
            com.secman.domain.VulnerabilityException.ExceptionType.ASSET -> {
                if (assetId != null) {
                    val count = vulnerabilityRepository.countByAssetId(assetId).toInt()
                    val page = vulnerabilityRepository.findByAssetId(assetId, pageable)
                    Pair(page.content, count)
                } else {
                    Pair(emptyList(), 0)
                }
            }
            com.secman.domain.VulnerabilityException.ExceptionType.CVE -> {
                val cveIds = targetValue.split(",").map { it.trim() }.filter { it.isNotEmpty() }
                if (assetId != null) {
                    val count = vulnerabilityRepository.countByVulnerabilityIdInAndAssetId(cveIds, assetId).toInt()
                    val page = vulnerabilityRepository.findByVulnerabilityIdInAndAssetId(cveIds, assetId, pageable)
                    Pair(page.content, count)
                } else {
                    val count = vulnerabilityRepository.countByVulnerabilityIdIn(cveIds).toInt()
                    val page = vulnerabilityRepository.findByVulnerabilityIdIn(cveIds, pageable)
                    Pair(page.content, count)
                }
            }
            com.secman.domain.VulnerabilityException.ExceptionType.AWS_ACCOUNT -> {
                val count = vulnerabilityRepository.countByAssetCloudAccountId(targetValue).toInt()
                val page = vulnerabilityRepository.findByAssetCloudAccountId(targetValue, pageable)
                Pair(page.content, count)
            }
        }

        // PERFORMANCE: Get active exceptions ONCE (cached for 5 minutes)
        val activeExceptions = getActiveExceptions()

        // Convert sample to DTOs with exception info
        val affectedDtos = sampleVulns.map { vuln ->
            // Calculate overdue status - pass pre-loaded exceptions to avoid N+1 queries
            val overdueInfo = calculateOverdueStatus(vuln, vuln.asset, activeExceptions)

            // Check if any active exception matches this vulnerability
            val matchingException = activeExceptions.firstOrNull { exception ->
                exception.matches(vuln, vuln.asset)
            }

            val hasException = matchingException != null
            val exceptionReason = matchingException?.reason

            VulnerabilityWithExceptionDto(
                id = vuln.id,
                asset = vuln.asset,
                assetId = vuln.asset.id!!,
                assetName = vuln.asset.name,
                assetIp = vuln.asset.ip,
                vulnerabilityId = vuln.vulnerabilityId,
                cvssSeverity = vuln.cvssSeverity,
                vulnerableProductVersions = vuln.vulnerableProductVersions,
                daysOpen = vuln.daysOpen,
                scanTimestamp = vuln.scanTimestamp,
                hasException = hasException,
                exceptionReason = exceptionReason,
                ageInDays = overdueInfo.ageInDays,
                overdueStatus = overdueInfo.status,
                daysOverdue = overdueInfo.daysOverdue,
                exceptionId = overdueInfo.exceptionId,
                exceptionEndDate = overdueInfo.exceptionEndDate
            )
        }

        log.info("Exception would affect {} vulnerabilities (showing {} sample)",
            totalCount, affectedDtos.size)
        return Pair(affectedDtos, totalCount)
    }

    /**
     * Cleanup duplicate vulnerabilities from the database
     *
     * A duplicate vulnerability is defined as:
     * - Same asset ID
     * - Same vulnerability ID (CVE)
     * - Same scan timestamp
     *
     * The cleanup process keeps the oldest record (lowest ID) and removes newer duplicates.
     * This is safe because the record with the lowest ID was created first and represents
     * the original entry.
     *
     * @return VulnerabilityCleanupResult with statistics about the cleanup operation
     */
    /**
     * Cleanup duplicate vulnerabilities using batched SQL-based approach
     * Feature: 073-memory-optimization
     *
     * Uses window function (ROW_NUMBER) to identify duplicates at SQL level,
     * avoiding loading all 300K+ vulnerabilities into memory.
     *
     * Processes in batches (configurable via memoryConfig.batchSize) to:
     * - Keep memory usage bounded
     * - Allow progress tracking
     * - Enable graceful interruption
     *
     * @return VulnerabilityCleanupResult with statistics about the cleanup operation
     */
    @Transactional
    open fun cleanupDuplicates(): com.secman.dto.VulnerabilityCleanupResult {
        log.info("Starting vulnerability duplicate cleanup (batched mode, batchSize={})", memoryConfig.batchSize)

        // Get total count first (for reporting)
        val totalScanned = vulnerabilityRepository.countAll().toInt()
        log.debug("Total vulnerabilities in database: {}", totalScanned)

        var duplicatesRemoved = 0
        var batchNumber = 0

        // Process duplicates in batches using SQL-level identification
        do {
            batchNumber++
            val duplicateIds = vulnerabilityRepository.findDuplicateIds(memoryConfig.batchSize)

            if (duplicateIds.isEmpty()) {
                log.debug("Batch {}: No more duplicates found", batchNumber)
                break
            }

            log.debug("Batch {}: Found {} duplicates to delete", batchNumber, duplicateIds.size)

            // Delete duplicates in this batch
            var batchDeleted = 0
            duplicateIds.forEach { id ->
                try {
                    vulnerabilityRepository.deleteById(id)
                    batchDeleted++
                    duplicatesRemoved++
                } catch (e: Exception) {
                    log.error("Failed to delete duplicate vulnerability ID {}: {}", id, e.message)
                }
            }

            log.info("Batch {}: Deleted {} duplicates (total removed: {})",
                batchNumber, batchDeleted, duplicatesRemoved)

            // Safety check: prevent infinite loop if duplicates keep appearing
            if (batchNumber > 1000) {
                log.warn("Exceeded 1000 batches, stopping cleanup. Total removed: {}", duplicatesRemoved)
                break
            }

        } while (true)

        val uniqueRemaining = totalScanned - duplicatesRemoved

        log.info("Cleanup completed: scanned={}, duplicatesRemoved={}, uniqueRemaining={}, batches={}",
            totalScanned, duplicatesRemoved, uniqueRemaining, batchNumber)

        return if (duplicatesRemoved > 0) {
            com.secman.dto.VulnerabilityCleanupResult.success(
                totalScanned = totalScanned,
                duplicatesFound = duplicatesRemoved, // In batched mode, found = removed
                duplicatesRemoved = duplicatesRemoved,
                uniqueRemaining = uniqueRemaining
            )
        } else {
            com.secman.dto.VulnerabilityCleanupResult.noCleanupNeeded(totalScanned)
        }
    }

    /**
     * Add or update vulnerability from CLI command
     * Feature: 052-cli-add-vulnerability
     *
     * Implements upsert pattern:
     * - If asset doesn't exist: create it with type=SERVER, owner=CLI-IMPORT
     * - If vulnerability with same CVE exists for asset: update it
     * - Otherwise: create new vulnerability
     *
     * @param request The add vulnerability request DTO
     * @return AddVulnerabilityResponseDto with operation result
     */
    @Transactional
    open fun addVulnerabilityFromCli(request: AddVulnerabilityRequestDto): AddVulnerabilityResponseDto {
        log.info("Adding vulnerability from CLI: hostname={}, cve={}, criticality={}, daysOpen={}",
            request.hostname, request.cve, request.criticality, request.daysOpen)

        // Step 1: Find or create asset
        var assetCreated = false
        var asset = assetRepository.findByNameIgnoreCase(request.hostname)

        if (asset == null) {
            // Create new asset with defaults
            asset = Asset(
                name = request.hostname,
                type = "SERVER",
                owner = "CLI-IMPORT"
            )
            asset.lastSeen = LocalDateTime.now()
            asset = assetRepository.save(asset)
            assetCreated = true
            log.info("Created new asset: id={}, name={}", asset.id, asset.name)
        } else {
            // Update lastSeen timestamp
            asset.lastSeen = LocalDateTime.now()
            asset = assetRepository.update(asset)
            log.debug("Found existing asset: id={}, name={}", asset.id, asset.name)
        }

        // Step 2: Map criticality to database format (title case)
        val cvssSeverity = when (request.criticality.uppercase()) {
            "CRITICAL" -> "Critical"
            "HIGH" -> "High"
            "MEDIUM" -> "Medium"
            "LOW" -> "Low"
            else -> request.criticality // Fallback to original
        }

        // Step 3: Calculate scan timestamp from daysOpen
        val scanTimestamp = LocalDateTime.now().minusDays(request.daysOpen.toLong())
        val daysOpenText = if (request.daysOpen == 1) "1 day" else "${request.daysOpen} days"

        // Step 4: Find existing vulnerability or create new one (upsert)
        val existingVuln = vulnerabilityRepository.findByAssetAndVulnerabilityId(asset, request.cve)
        val operation: String

        val vulnerability = if (existingVuln != null) {
            // Update existing vulnerability
            existingVuln.cvssSeverity = cvssSeverity
            existingVuln.daysOpen = daysOpenText
            existingVuln.scanTimestamp = scanTimestamp
            existingVuln.importTimestamp = LocalDateTime.now()
            vulnerabilityRepository.update(existingVuln)
            operation = "UPDATED"
            log.info("Updated existing vulnerability: id={}, cve={}", existingVuln.id, request.cve)
            existingVuln
        } else {
            // Create new vulnerability
            val newVuln = Vulnerability(
                asset = asset,
                vulnerabilityId = request.cve,
                cvssSeverity = cvssSeverity,
                daysOpen = daysOpenText,
                scanTimestamp = scanTimestamp
            )
            newVuln.importTimestamp = LocalDateTime.now()
            vulnerabilityRepository.save(newVuln)
            operation = "CREATED"
            log.info("Created new vulnerability: id={}, cve={}", newVuln.id, request.cve)
            newVuln
        }

        // Step 6: Synchronize importTimestamp for all other vulnerabilities on this asset
        // This ensures they are all considered part of the "latest" batch in DomainVulnsView
        // which filters by ranking importTimestamp (fix for CLI sequential imports hiding previous vulns)
        if (!assetCreated && vulnerability.importTimestamp != null) {
            val otherVulns = vulnerabilityRepository.findByAssetId(
                asset.id!!, 
                io.micronaut.data.model.Pageable.UNPAGED
            ).content

            val vulnsToUpdate = otherVulns.filter { it.id != vulnerability.id }

            if (vulnsToUpdate.isNotEmpty()) {
                log.info("Synchronizing importTimestamp for {} other vulnerabilities on asset {}", 
                    vulnsToUpdate.size, asset.name)

                vulnsToUpdate.forEach { v ->
                    v.importTimestamp = vulnerability.importTimestamp
                    vulnerabilityRepository.update(v)
                }
            }
        }

        // Step 5: Build response message
        val message = if (assetCreated) {
            "Asset ${asset.name} created. Vulnerability ${request.cve} added."
        } else if (operation == "UPDATED") {
            "Vulnerability ${request.cve} updated on asset ${asset.name}"
        } else {
            "Vulnerability ${request.cve} added to asset ${asset.name}"
        }

        return AddVulnerabilityResponseDto(
            success = true,
            message = message,
            assetId = asset.id!!,
            assetName = asset.name,
            assetCreated = assetCreated,
            vulnerabilityId = request.cve,
            operation = operation
        )
    }
}

/**
 * Current Vulnerability Export Utility
 *
 * Client-side Excel generation for Current Vulnerabilities data using ExcelJS
 *
 * Features:
 * - Generates Excel workbook with vulnerability data
 * - Summary sheet with statistics (total, by severity, by exception status)
 * - Severity-based cell coloring (Critical=Red, High=Yellow, Medium=Blue, Low=Green)
 * - Auto-filter enabled for easy filtering in Excel
 * - Frozen header row
 *
 * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
 */

import ExcelJS from 'exceljs';
import type { CurrentVulnerability } from '../services/vulnerabilityManagementService';

export interface CurrentVulnerabilityExportOptions {
    exportDate: Date;
    filters?: {
        severity?: string;
        system?: string;
        exceptionStatus?: string;
        product?: string;
        adDomain?: string;
        cloudAccountId?: string;
    };
}

/**
 * Export current vulnerabilities to Excel file
 *
 * @param vulnerabilities List of vulnerabilities to export
 * @param options Export options including filters applied
 * @returns Promise that resolves when file is generated and downloaded
 */
export async function exportCurrentVulnerabilitiesToExcel(
    vulnerabilities: CurrentVulnerability[],
    options: CurrentVulnerabilityExportOptions
): Promise<void> {
    const workbook = new ExcelJS.Workbook();

    // Set workbook properties
    workbook.creator = 'Secman';
    workbook.created = new Date();
    workbook.modified = new Date();
    workbook.lastModifiedBy = 'Secman';

    // Create summary sheet
    const summarySheet = workbook.addWorksheet('Summary');

    // Add summary information
    summarySheet.columns = [
        { header: 'Property', key: 'property', width: 30 },
        { header: 'Value', key: 'value', width: 50 },
    ];

    // Calculate severity counts
    const severityCounts = vulnerabilities.reduce((acc, vuln) => {
        const severity = vuln.cvssSeverity || 'Unknown';
        acc[severity] = (acc[severity] || 0) + 1;
        return acc;
    }, {} as Record<string, number>);

    // Calculate overdue status counts
    const overdueStatusCounts = vulnerabilities.reduce((acc, vuln) => {
        const status = vuln.overdueStatus || 'Unknown';
        acc[status] = (acc[status] || 0) + 1;
        return acc;
    }, {} as Record<string, number>);

    // Calculate exception counts
    const exceptedCount = vulnerabilities.filter(v => v.hasException).length;
    const notExceptedCount = vulnerabilities.length - exceptedCount;

    const summaryRows: { property: string; value: string }[] = [
        { property: 'Export Date', value: options.exportDate.toLocaleString() },
        { property: '', value: '' },
        { property: 'Applied Filters', value: '' },
    ];

    // Add filter info
    const filters = options.filters || {};
    if (filters.severity) {
        summaryRows.push({ property: '  Severity', value: filters.severity });
    }
    if (filters.system) {
        summaryRows.push({ property: '  System', value: filters.system });
    }
    if (filters.exceptionStatus) {
        summaryRows.push({ property: '  Exception Status', value: filters.exceptionStatus });
    }
    if (filters.product) {
        summaryRows.push({ property: '  Product', value: filters.product });
    }
    if (filters.adDomain) {
        summaryRows.push({ property: '  AD Domain', value: filters.adDomain });
    }
    if (filters.cloudAccountId) {
        summaryRows.push({ property: '  AWS Account ID', value: filters.cloudAccountId });
    }

    const hasFilters = Object.values(filters).some(v => v);
    if (!hasFilters) {
        summaryRows.push({ property: '  (No filters applied)', value: '' });
    }

    summaryRows.push(
        { property: '', value: '' },
        { property: 'Vulnerability Summary', value: '' },
        { property: '  Total Vulnerabilities', value: String(vulnerabilities.length) },
        { property: '', value: '' },
        { property: 'By Severity', value: '' },
        { property: '  Critical', value: String(severityCounts['Critical'] || 0) },
        { property: '  High', value: String(severityCounts['High'] || 0) },
        { property: '  Medium', value: String(severityCounts['Medium'] || 0) },
        { property: '  Low', value: String(severityCounts['Low'] || 0) },
        { property: '  Unknown', value: String(severityCounts['Unknown'] || 0) },
        { property: '', value: '' },
        { property: 'By Overdue Status', value: '' },
        { property: '  OVERDUE', value: String(overdueStatusCounts['OVERDUE'] || 0) },
        { property: '  EXCEPTED', value: String(overdueStatusCounts['EXCEPTED'] || 0) },
        { property: '  OK', value: String(overdueStatusCounts['OK'] || 0) },
        { property: '', value: '' },
        { property: 'By Exception Status', value: '' },
        { property: '  Excepted', value: String(exceptedCount) },
        { property: '  Not Excepted', value: String(notExceptedCount) },
    );

    summarySheet.addRows(summaryRows);

    // Style summary sheet header
    summarySheet.getRow(1).font = { bold: true, size: 12, color: { argb: 'FFFFFFFF' } };
    summarySheet.getRow(1).fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: 'FF4472C4' },
    };

    // Create vulnerabilities sheet
    const vulnSheet = workbook.addWorksheet('Vulnerabilities');
    vulnSheet.columns = [
        { header: 'Asset Name', key: 'assetName', width: 30 },
        { header: 'IP Address', key: 'assetIp', width: 15 },
        { header: 'CVE ID', key: 'vulnerabilityId', width: 18 },
        { header: 'Severity', key: 'cvssSeverity', width: 12 },
        { header: 'Product', key: 'vulnerableProductVersions', width: 40 },
        { header: 'Days Open', key: 'daysOpen', width: 12 },
        { header: 'Scan Date', key: 'scanTimestamp', width: 20 },
        { header: 'Overdue Status', key: 'overdueStatus', width: 15 },
        { header: 'Has Exception', key: 'hasException', width: 14 },
        { header: 'Exception Reason', key: 'exceptionReason', width: 35 },
    ];

    // Add vulnerability rows
    vulnerabilities.forEach((vuln) => {
        const row = vulnSheet.addRow({
            assetName: vuln.assetName || '-',
            assetIp: vuln.assetIp || '-',
            vulnerabilityId: vuln.vulnerabilityId || '-',
            cvssSeverity: vuln.cvssSeverity || 'Unknown',
            vulnerableProductVersions: vuln.vulnerableProductVersions || '-',
            daysOpen: vuln.daysOpen || '-',
            scanTimestamp: vuln.scanTimestamp ? new Date(vuln.scanTimestamp).toLocaleString() : '-',
            overdueStatus: vuln.overdueStatus || 'Unknown',
            hasException: vuln.hasException ? 'Yes' : 'No',
            exceptionReason: vuln.exceptionReason || '-',
        });

        // Color-code severity cells
        const severityCell = row.getCell('cvssSeverity');
        const severityColor = getSeverityColor(vuln.cvssSeverity);
        if (severityColor) {
            severityCell.fill = {
                type: 'pattern',
                pattern: 'solid',
                fgColor: { argb: severityColor.bg },
            };
            severityCell.font = { color: { argb: severityColor.text }, bold: true };
        }

        // Color-code overdue status cells
        const overdueCell = row.getCell('overdueStatus');
        const overdueColor = getOverdueStatusColor(vuln.overdueStatus);
        if (overdueColor) {
            overdueCell.fill = {
                type: 'pattern',
                pattern: 'solid',
                fgColor: { argb: overdueColor.bg },
            };
            overdueCell.font = { color: { argb: overdueColor.text }, bold: true };
        }

        // Color-code exception cells
        const exceptionCell = row.getCell('hasException');
        if (vuln.hasException) {
            exceptionCell.fill = {
                type: 'pattern',
                pattern: 'solid',
                fgColor: { argb: 'FF198754' }, // Green
            };
            exceptionCell.font = { color: { argb: 'FFFFFFFF' }, bold: true };
        }
    });

    // Style header row
    styleHeaderRow(vulnSheet, 'FF2C3E50');

    // Add auto-filter
    vulnSheet.autoFilter = {
        from: 'A1',
        to: `J${vulnerabilities.length + 1}`,
    };

    // Freeze header row
    vulnSheet.views = [{ state: 'frozen', ySplit: 1 }];

    // Generate buffer and trigger download
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], {
        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    });

    // Create filename
    const dateStr = new Date().toISOString().split('T')[0];

    // Create download link
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `CurrentVulnerabilities_${dateStr}.xlsx`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);
}

/**
 * Get color codes for severity level
 */
function getSeverityColor(severity: string | null): { bg: string; text: string } | null {
    const sev = severity?.toLowerCase() || '';
    if (sev.includes('critical')) return { bg: 'FFDC3545', text: 'FFFFFFFF' }; // Red
    if (sev.includes('high')) return { bg: 'FFFFC107', text: 'FF000000' }; // Yellow
    if (sev.includes('medium')) return { bg: 'FF17A2B8', text: 'FFFFFFFF' }; // Blue
    if (sev.includes('low')) return { bg: 'FF28A745', text: 'FFFFFFFF' }; // Green
    return null;
}

/**
 * Get color codes for overdue status
 */
function getOverdueStatusColor(status: string | undefined): { bg: string; text: string } | null {
    if (!status) return null;
    const s = status.toUpperCase();
    if (s === 'OVERDUE') return { bg: 'FFDC3545', text: 'FFFFFFFF' }; // Red
    if (s === 'EXCEPTED') return { bg: 'FF17A2B8', text: 'FFFFFFFF' }; // Blue (shield)
    if (s === 'OK') return { bg: 'FF28A745', text: 'FFFFFFFF' }; // Green
    return null;
}

/**
 * Style the header row of a worksheet
 */
function styleHeaderRow(sheet: ExcelJS.Worksheet, color: string): void {
    const headerRow = sheet.getRow(1);
    headerRow.font = { bold: true, size: 11, color: { argb: 'FFFFFFFF' } };
    headerRow.fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: color },
    };
    headerRow.alignment = { vertical: 'middle', horizontal: 'left' };
    headerRow.height = 22;

    // Add borders
    headerRow.eachCell((cell) => {
        cell.border = {
            top: { style: 'thin' },
            left: { style: 'thin' },
            bottom: { style: 'medium' },
            right: { style: 'thin' },
        };
    });

    // Enable text wrap for all cells
    sheet.eachRow((row, rowNumber) => {
        if (rowNumber > 1) {
            row.eachCell((cell) => {
                cell.alignment = { ...cell.alignment, wrapText: true, vertical: 'top' };
                cell.border = {
                    top: { style: 'thin', color: { argb: 'FFE0E0E0' } },
                    left: { style: 'thin', color: { argb: 'FFE0E0E0' } },
                    bottom: { style: 'thin', color: { argb: 'FFE0E0E0' } },
                    right: { style: 'thin', color: { argb: 'FFE0E0E0' } },
                };
            });
        }
    });
}

